import { useState, useCallback, useEffect } from 'react'
import styled, { css } from 'styled-components'

import { CartItem } from '../../../../app-state/cart'
import { toCurrency } from '../../../../helpers'
import { breakpoints } from '../../../../styles/breakpoints'
import { Button } from '../../../../components/Button'
import { Body } from '../../../../components/typography/Body'
import { Heading } from '../../../../components/typography/Heading'
import { Modal } from '../../../../components/Modal'

const StyledBody = styled(Body)`
  margin: 0;
  margin-top: 8px;
`

const StyledButton = styled(Button)`
  flex: 1;
`

const ButtonsContainer = styled.div`
  display: flex;
  align-items: center;
  justify-content: space-around;
  flex: 0.45;
  margin-bottom: 1.5rem;
  margin-right: 0;
  @media ${breakpoints.M} {
    margin-bottom: 0;
    margin-right: 1.5rem;
    justify-content: space-between;
  }
`

const TopContainer = styled.div(
  ({ theme: { color } }) => css`
    padding: 2.5rem 1.5rem;
    background: ${color.overlayHeader};
    border-radius: 16px 16px 0px 0px;
  `
)

const BottomContainer = styled.div`
  padding: 1.5rem;
  display: flex;
  flex-direction: column;
  @media ${breakpoints.M} {
    flex-direction: row;
  }
`

type FoodItemModalProps = {
  item?: CartItem
  cartItems: CartItem[]
  onClose: () => void
  onItemSave: (item: CartItem) => void
  onItemRemove: (item: CartItem) => void
}

export const FoodItemModal = ({
  item,
  cartItems,
  onClose,
  onItemSave,
  onItemRemove,
}: FoodItemModalProps) => {
  const [quantity, setQuantity] = useState(0)

  const saveItem = useCallback(() => {
    if (item) {
      if (quantity === 0) {
        onItemRemove(item)
      } else {
        onItemSave({ ...item, quantity })
      }
    }

    onClose()
  }, [quantity, onClose, onItemRemove, item, onItemSave])

  useEffect(() => {
    const cartItem = item && cartItems.find((c) => c.id === item.id)
    setQuantity(cartItem?.quantity || 1)
    return () => setQuantity(0)
  }, [cartItems, item])

  return (
    <Modal isOpen={!!item} onClose={onClose}>
      {item && (
        <div>
          <TopContainer>
            <Heading>{item.name}</Heading>
            <StyledBody>{item.description}</StyledBody>
          </TopContainer>
          <BottomContainer>
            <ButtonsContainer>
              <Button
                aria-label="decrease quantity by one"
                round
                clear
                icon="minus"
                onClick={() => setQuantity(quantity - 1)}
                disabled={quantity <= 1}
              />
              <Body type="span">{quantity}</Body>
              <Button
                aria-label="increase quantity by one"
                round
                clear
                icon="plus"
                onClick={() => setQuantity(quantity + 1)}
                disabled={quantity >= 10}
              />
            </ButtonsContainer>
            <StyledButton aria-label="confirm" onClick={saveItem}>
              add for {toCurrency(item.price * quantity)}
            </StyledButton>
          </BottomContainer>
        </div>
      )}
    </Modal>
  )
}

import * as React from 'react'
import { CSSTransition } from 'react-transition-group'

import { Portal } from '../Portal'
import { useKey } from '../../hooks/useKeyboard'
import { Button } from '../Button'
import { useLockBodyScroll } from '../../hooks/useBodyScrollLock'

import { ModalContent, TopBar, Backdrop } from './Modal.styles'

type ModalProps = {
  isOpen: boolean
  onClose: () => void
}

export const Modal: React.FC<React.PropsWithChildren<ModalProps>> = ({
  children,
  isOpen,
  onClose,
}) => {
  useKey('escape', onClose)
  useLockBodyScroll(isOpen)
  const contentRef = React.useRef(null)
  const backdropRef = React.useRef(null)

  return (
    <Portal selector="#modal">
      <CSSTransition
        in={isOpen}
        timeout={300}
        classNames="modal"
        unmountOnExit
        nodeRef={contentRef}
      >
        <ModalContent data-testid="modal" ref={contentRef}>
          <TopBar>
            <Button
              data-testid="modal-close-btn"
              onClick={onClose}
              clear
              round
              icon="cross"
              aria-label="close modal"
              iconSize={16}
            />
          </TopBar>
          {children}
        </ModalContent>
      </CSSTransition>

      <CSSTransition
        in={isOpen}
        timeout={300}
        classNames="backdrop"
        unmountOnExit
        nodeRef={backdropRef}
      >
        <Backdrop data-testid="modal-backdrop" ref={backdropRef} onClick={onClose} />
      </CSSTransition>
    </Portal>
  )
}

